      case b: java.lang.Boolean => if (b) "true" else "false"
      case n: java.lang.Byte => n.toString
      case n: java.lang.Short => n.toString
      case n: java.lang.Integer => n.toString
      case n: java.lang.Long => n.toString
      case n: java.lang.Float =>
        if (n.isNaN || n.isInfinite) "null" else n.toString
      case n: java.lang.Double =>
        if (n.isNaN || n.isInfinite) "null" else n.toString
      case d: java.math.BigDecimal => d.toString
      case d: scala.math.BigDecimal => d.toString
      case ts: java.sql.Timestamp => "\"" + escapeJson(ts.toString) + "\""
      case d: java.sql.Date => "\"" + escapeJson(d.toString) + "\""
      case a: Array[Byte] => "\"" + java.util.Base64.getEncoder.encodeToString(a) + "\""
      case seq: scala.collection.Seq[_] =>
        val sb = new StringBuilder
        sb.append('[')
        var i = 0
        seq.foreach { x =>
          if (i > 0) sb.append(',')
          sb.append(renderJsonValue(x))
          i += 1
        }
        sb.append(']')
        sb.toString()
      case m: scala.collection.Map[_, _] =>
        val sb = new StringBuilder
        sb.append('{')
        var i = 0
        m.foreach { case (k, vv) =>
          if (i > 0) sb.append(',')
          sb.append('"').append(escapeJson(String.valueOf(k))).append('"').append(':').append(renderJsonValue(vv))
          i += 1
        }
        sb.append('}')
        sb.toString()
      case r: org.apache.spark.sql.Row =>
        "\"" + escapeJson(r.toString) + "\""
      case other =>
        "\"" + escapeJson(String.valueOf(other)) + "\""
    }

    private def escapeJson(s: String): String = {
