      var i = 0
      while (i < s.length) {
        s.charAt(i) match {
          case '"'  => sb.append("\\\"")
          case '\\' => sb.append("\\\\")
          case '\b' => sb.append("\\b")
          case '\f' => sb.append("\\f")
          case '\n' => sb.append("\\n")
          case '\r' => sb.append("\\r")
          case '\t' => sb.append("\\t")
          case c if c < ' ' => sb.append(f"\\u${c.toInt}%04x")
          case c => sb.append(c)
        }
        i += 1
      }
      sb.toString()
    }

    private def renderResponse(resp: QueryResponse): String = {
      val sb = new StringBuilder
      sb.append('{')
      sb.append("\"requestId\":\"").append(escapeJson(resp.requestId)).append('"')
      sb.append(",\"status\":\"").append(escapeJson(resp.status)).append('"')
      resp.message.foreach(m => sb.append(",\"message\":\"").append(escapeJson(m)).append('"'))
      sb.append(",\"elapsedMs\":").append(resp.elapsedMs)
      sb.append(",\"truncated\":").append(if (resp.truncated) "true" else "false")
      resp.schema.foreach(s => sb.append(",\"schema\":").append(s))
      resp.data.foreach(d => sb.append(",\"data\":\"").append(escapeJson(d)).append('"'))
      sb.append('}')
      sb.toString()
    }

    private def readBody(exchange: HttpExchange, maxBytes: Int): String = {
