      Some(QueryRequest(
        query = query,
        database = strField("database").orElse(strField("db")),
        catalog = strField("catalog"),
        maxRows = intField("maxRows"),
        timeoutMs = longField("timeoutMs"),
        user = strField("user"),
        requestId = strField("requestId"),
        format = strField("format")
