    private def extractJsonNumberField(json: String, field: String): Option[String] = {
      val re = (""""""" + java.util.regex.Pattern.quote(field) + """"\s*:\s*([-]?\d+)""").r
      re.findFirstMatchIn(json).map(_.group(1))
    }

    private def unescapeJsonString(s: String): String = {
      val sb = new StringBuilder
      var i = 0
      while (i < s.length) {
        val c = s.charAt(i)
        if (c != '\\') {
          sb.append(c); i += 1
        } else {
          if (i + 1 >= s.length) { sb.append('\\'); i += 1 }
          else {
            s.charAt(i + 1) match {
              case '"' => sb.append('"'); i += 2
              case '\\' => sb.append('\\'); i += 2
              case '/' => sb.append('/'); i += 2
              case 'b' => sb.append('\b'); i += 2
              case 'f' => sb.append('\f'); i += 2
              case 'n' => sb.append('\n'); i += 2
              case 'r' => sb.append('\r'); i += 2
              case 't' => sb.append('\t'); i += 2
              case 'u' =>
                if (i + 6 <= s.length) {
                  val hex = s.substring(i + 2, i + 6)
                  Try(Integer.parseInt(hex, 16)).toOption match {
                    case Some(cp) => sb.append(cp.toChar)
                    case None => sb.append("\\u").append(hex)
                  }
                  i += 6
                } else {
                  sb.append("\\u"); i += 2
                }
              case other =>
                sb.append(other); i += 2
            }
          }
        }
      }
      sb.toString()
    }
  }

  private def writeJson(exchange: HttpExchange, status: Int, body: String): Unit = {
    val bytes = body.getBytes(StandardCharsets.UTF_8)
    val headers = exchange.getResponseHeaders
    headers.set("Content-Type", "application/json; charset=utf-8")
    headers.set("Cache-Control", "no-store")
    exchange.sendResponseHeaders(status, bytes.length)
    val os = exchange.getResponseBody
    try os.write(bytes)
    finally os.close()
  }
